def is_prime(n):
    if n <= 1:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True
num = int(input('Enter a number: '))
if is_prime(num):
    print(num, 'is a prime number')
else:
    print(num, 'is not a prime number')

In Python, conditional statements are used to execute different blocks of code based on a condition. The if-else statement is used to check if a condition is true or false. If the condition is true, the code inside the if block is executed, otherwise, the code inside the else block is executed. For example: x = 5
if x > 10:
    print('x is greater than 10')
else:
    print('x is less than or equal to 10')

def sum_numbers(numbers):
    if len(numbers) == 1:
        return numbers[0]
    else:
        return numbers[0] + sum_numbers(numbers[1:])
numbers = [1, 2, 3, 4, 5]
print('Sum of numbers:', sum_numbers(numbers))
